#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <iostream>
#include <omp.h>

using namespace std;

#define HALO     1
#define STR_SIZE 256
#define M_SEED   9

#define IN_RANGE(x, min, max) ((x)>= (min) && (x)<= (max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<= (b) ? (a) : (b))

int   rows = -1, cols = -1;
int   Ne = rows * cols;
int*  data;
int** wall;
int*  result;
int   pyramid_height = -1;
int   verbose = 0;

#ifdef TIMING
	struct timeval tv;
	struct timeval tv_total_start, tv_total_end;
	struct timeval tv_init_end;
	struct timeval tv_h2d_start, tv_h2d_end;
	struct timeval tv_d2h_start, tv_d2h_end;
	struct timeval tv_kernel_start, tv_kernel_end;
	struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
	struct timeval tv_close_start, tv_close_end;
	float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
		  d2h_time = 0, close_time = 0, total_time = 0;
#endif

void init(int argc, char** argv)
{
    int cur_arg;
	for (cur_arg = 1; cur_arg<argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-c") == 0) {
            if (argc >= cur_arg + 1) {
                cols = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-r") == 0) {
            if (argc >= cur_arg + 1) {
                rows = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-h") == 0) {
            if (argc >= cur_arg + 1) {
                pyramid_height = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        if (strcmp(argv[cur_arg], "-v") == 0) {
			verbose = 1;
        }
    }

	if (cols < 0 || rows < 0 || pyramid_height < 0)
	{
        fprintf(stderr, "usage: %s <-r rows> <-c cols> <-h pyramid_height> [-v]\n", argv[0]);
		exit(0);
	}
	data = new int[rows * cols];
	wall = new int*[rows];
	for (int n = 0; n < rows; n++)
	{
		wall[n] = data + cols * n;
	}
	result = new int[cols];

	int seed = M_SEED;
	srand(seed);

	for (int i = 0; i < rows; i++)
	{
		for (int j = 0; j < cols; j++)
		{
			wall[i][j] = rand() % 10;
		}
	}
#ifdef BENCH_PRINT
	for (int i = 0; i < rows; i++)
	{
		for (int j = 0; j < cols; j++)
		{
			printf("%d ", wall[i][j]);
		}
		printf("\n");
	}
#endif
}

void fatal(char *s)
{
	fprintf(stderr, "error: %s\n", s);
}

// Helper function to simulate the kernel logic for a single block
void dynproc_kernel_sim(int iteration,
                        int* gpuWall,
                        int* gpuSrc,
                        int* gpuResults,
                        int cols,
                        int rows,
                        int startStep,
                        int border,
                        int HALO,
                        int BLOCK_SIZE,
                        int bx,
                        int* outputBuffer)
{
	// Simulate local memory
	int* prev = new int[BLOCK_SIZE];
	int* result = new int[BLOCK_SIZE];

	int tx; // Thread index within block

	// Determine block boundaries
	int small_block_cols = BLOCK_SIZE - (iteration*HALO*2);
	int blkX = (small_block_cols*bx) - border;
	int blkXmax = blkX+BLOCK_SIZE-1;

	// Determine valid range within the block
	int validXmin = (blkX < 0) ? -blkX : 0;
	int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

	// Initialize local memory and compute
	for (tx = 0; tx < BLOCK_SIZE; tx++) {
		int xidx = blkX+tx;

		int W = tx-1;
		int E = tx+1;

		W = (W < validXmin) ? validXmin : W;
		E = (E > validXmax) ? validXmax : E;

		bool isValid = IN_RANGE(tx, validXmin, validXmax);

		if(IN_RANGE(xidx, 0, cols-1))
		{
			prev[tx] = gpuSrc[xidx];
		} else {
			prev[tx] = 0; // Safe default for out of bounds
		}
	}

	// Implicit barrier after init

	bool computed;
	for (int i = 0; i < iteration; i++)
	{
		computed = false;

		// Parallel loop over threads in the block
		for (tx = 0; tx < BLOCK_SIZE; tx++) {
			int xidx = blkX+tx;
			int W = tx-1;
			int E = tx+1;
			W = (W < validXmin) ? validXmin : W;
			E = (E > validXmax) ? validXmax : E;
			bool isValid = IN_RANGE(tx, validXmin, validXmax);

			if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid )
			{
				computed = true;
				int left = prev[W];
				int up = prev[tx];
				int right = prev[E];
				int shortest = MIN(left, up);
				shortest = MIN(shortest, right);

				int index = cols*(startStep+i)+xidx;
				result[tx] = shortest + gpuWall[index];

				if (tx==11 && i==0)
				{
					int bufIndex = gpuSrc[xidx];
					if (bufIndex >= 0 && bufIndex < 16384) {
						outputBuffer[bufIndex] = 1;
					}
				}
			}
		}

		// Implicit barrier

		if(i==iteration-1)
		{
			break;
		}

		// Update prev for next iteration
		for (tx = 0; tx < BLOCK_SIZE; tx++) {
			if (IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && IN_RANGE(blkX+tx, 0, cols-1)) {
				// Only update if this thread computed
				// We need to check if the specific tx computed in the previous step
				// The condition IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) determines if it computed
				if (IN_RANGE(tx, i+1, BLOCK_SIZE-i-2)) {
					prev[tx] = result[tx];
				}
			}
		}
		// Implicit barrier
	}

	// Write results back to global memory
	for (tx = 0; tx < BLOCK_SIZE; tx++) {
		int xidx = blkX+tx;
		if (IN_RANGE(xidx, 0, cols-1)) {
			// Check if this thread computed something in the last iteration
			if (IN_RANGE(tx, iteration-1+1, BLOCK_SIZE-(iteration-1)-2)) {
				gpuResults[xidx] = result[tx];
			}
		}
	}

	delete[] prev;
	delete[] result;
}

int main(int argc, char** argv)
{
	init(argc, argv);

	int borderCols = (pyramid_height) * HALO;

	int size = rows * cols;

#ifdef  TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

#ifdef  TIMING
    gettimeofday(&tv_init_end, NULL);
	tvsub(&tv_init_end, &tv_total_start, &tv);
	init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    int* h_outputBuffer = (int*)malloc(16384 * sizeof(int));
    for (int i = 0; i < 16384; i++) {
        h_outputBuffer[i] = 0;
	}

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    // gpuWall corresponds to data + cols (skipping first row)
    int* gpuWall = data + cols;

    // Two buffers for results (src and final_ret)
    int* d_gpuResult0 = new int[cols];
    int* d_gpuResult1 = new int[cols];

    // Initialize d_gpuResult0 with first row of data
    for(int i=0; i<cols; i++) d_gpuResult0[i] = data[i];
    for(int i=0; i<cols; i++) d_gpuResult1[i] = 0;

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
    h2d_time = 0; // No explicit transfer time in OpenMP sequential setup
#endif

	int src = 1, final_ret = 0;

	// Determine block size. In OpenCL, this was derived from hardware.
	// We use a fixed reasonable block size or divide cols evenly.
	// To mimic the original logic where blocks cover the width:
	// The original code calculates small_block_cols based on iteration.
	// We need a fixed BLOCK_SIZE for the simulation. 
	// Let's assume a block size of 256 or similar, or calculate based on cols.
	// The original OpenCL code set gwSize to rows*cols but the kernel only uses 1D x.
	// Actually, the kernel uses get_group_id(0) and get_local_size(0).
	// It seems to process the width (cols) in blocks.
	// Let's set BLOCK_SIZE to 256 or a divisor of cols.
	int BLOCK_SIZE = 256;
	if (cols < BLOCK_SIZE) BLOCK_SIZE = cols;
	// Ensure BLOCK_SIZE is large enough for the pyramid height logic
	if (BLOCK_SIZE < pyramid_height * 2 + 2) {
		BLOCK_SIZE = pyramid_height * 2 + 2;
		if (BLOCK_SIZE > cols) BLOCK_SIZE = cols;
	}

	// Number of blocks needed to cover cols
	// The mapping in OpenCL: blkX = (small_block_cols*bx) - border
	// This implies blocks are spaced by small_block_cols.
	// However, small_block_cols depends on iteration.
	// In the original code, the kernel is launched once per pyramid step.
	// The block count must be sufficient to cover the active region.
	// Let's calculate max blocks needed.
	// The effective width processed per block shrinks.
	// To be safe and simple, we map blocks to cover the entire cols range.
	int num_blocks = (cols + BLOCK_SIZE - 1) / BLOCK_SIZE;
	if (num_blocks == 0) num_blocks = 1;

	for (int t = 0; t < rows - 1; t += pyramid_height)
	{
		int temp = src;
		src = final_ret;
		final_ret = temp;

		int arg0 = MIN(pyramid_height, rows-t-1);
		int theHalo = HALO;
		int startStep = t;

		int* currentSrc = (src == 0) ? d_gpuResult0 : d_gpuResult1;
		int* currentDest = (final_ret == 0) ? d_gpuResult0 : d_gpuResult1;

#ifdef TIMING
		gettimeofday(&tv_kernel_start, NULL);
#endif

		// Parallelize over blocks
		#pragma omp parallel for
		for (int bx = 0; bx < num_blocks; bx++) {
			dynproc_kernel_sim(arg0,
							   gpuWall,
							   currentSrc,
							   currentDest,
							   cols,
							   rows,
							   startStep,
							   borderCols,
							   theHalo,
							   BLOCK_SIZE,
							   bx,
							   h_outputBuffer);
		}

#ifdef TIMING
		gettimeofday(&tv_kernel_end, NULL);
		tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
		kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif
	}

#ifdef TIMING
    d2h_time = 0;
#endif

	// Copy result to output array
	for(int i=0; i<cols; i++) {
		result[i] = (final_ret == 0) ? d_gpuResult0[i] : d_gpuResult1[i];
	}

	h_outputBuffer[16383] = '\0';

#ifdef BENCH_PRINT
	for (int i = 0; i < cols; i++)
		printf("%d ", data[i]);
	printf("\n");
	for (int i = 0; i < cols; i++)
		printf("%d ", result[i]);
	printf("\n");
#endif

#ifdef  TIMING
	gettimeofday(&tv_close_start, NULL);
#endif

	delete[] d_gpuResult0;
	delete[] d_gpuResult1;

#ifdef  TIMING
	gettimeofday(&tv_close_end, NULL);
	tvsub(&tv_close_end, &tv_close_start, &tv);
	close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	delete[] data;
	delete[] wall;
	delete[] result;
	free(h_outputBuffer);

	return EXIT_SUCCESS;
}
